import React from "react";
import { Link } from "react-router-dom";
import "./Section.css";

function Home() {
  return (
    <div>
      {/* Hero Section */}
      <section className="hero">
        <h1>Your Health, Our Priority</h1>
        <p>Connecting people to better healthcare solutions.</p>
        <button className="get-started">Get Started</button>
      </section>

      {/* Service Cards */}
      <section className="services">
        <Link to="/pathology" className="card">
          <h3>Pathology Services</h3>
          <p>Find and book appointments with leading pathology labs.</p>
        </Link>

        <Link to="/bloodbank" className="card">
          <h3>Blood Bank Information</h3>
          <p>Get real-time info on blood availability and connect with banks.</p>
        </Link>

        <Link to="/consultancy" className="card">
          <h3>Online Consultancy</h3>
          <p>Consult healthcare professionals online for guidance.</p>
        </Link>

        <Link to="/medicine" className="card">
          <h3>Medicine Delivery</h3>
          <p>Order prescribed medicines and get them delivered.</p>
        </Link>
      </section>
    </div>
  );
}

export default Home;
